    import subprocess

    editor = self.get_editor()
    environ: dict[str, str] | None = None

    if self.env:
        environ = os.environ.copy()
        environ.update(self.env)

    exec_name = editor.split()[0]

    if os.path.basename(exec_name) in ("vim", "gvim", "vimdiff", "nvim"):
